frappe.listview_settings['Fiche Transfert Credit'] = {
    onload(listview) {

        async function print_selected() {
            const selected = listview.get_checked_items();

            if (!selected.length) {
                frappe.msgprint(__('Veuillez sélectionner un mandat à imprimer.'));
                return;
            }

            if (selected.length > 1) {
                frappe.msgprint(__('Vous devez sélectionner un seul un mandat.'));
                return;
            }

            const doc = selected[0];

            // Format fixe "Mondat"
            const print_format = 'movement credit';

            // Générer l’URL pour l’impression
            const url = frappe.urllib.get_full_url(
                `/printview?doctype=Fiche Transfert Credit` +
                `&name=${encodeURIComponent(doc.name)}` +
                `&format=${encodeURIComponent(print_format)}` +
                `&no_letterhead=0`
            );

            // Ouvrir l’aperçu d’impression dans une nouvelle fenêtre
            const w = window.open(url, '_blank');

            if (w) {
                w.onload = () => w.print();
            } else {
                frappe.msgprint(__('Popup bloquée pour {0}', [doc.name]));
            }
        }

        // Ajouter le bouton d’impression
        listview.page.add_inner_button(
            '<i class="fa fa-print"></i> Imprimer',
            () => { print_selected(); }
        );

        // Style du bouton
        const print_button = listview.page.wrapper.find('.dropdown-toggle:contains("Imprimer")');

        if (print_button.length) {
            print_button.css({
                'background-color': '#007bff',
                'color': 'white',
                'border-color': '#007bff'
            });
        }
    }
};

frappe.ui.form.on('Fiche Budgetaire', {

