frappe.listview_settings['Fiche Budgetaire'] = {
    onload(listview) {

        async function print_selected() {
            const selected = listview.get_checked_items();

            if (!selected.length) {
                frappe.msgprint(__('Please select at least one Budget Article to print.'));
                return;
            }

            if (selected.length > 1) {
                frappe.msgprint(__('You should select only one Budget Article to print.'));
                return;
            }

            const doc = selected[0];

            // Determine the print format based on the value of type_fiche
            let print_format = '';
            if (doc.type_fiche === 'Économie') {
                print_format = 'fiche economie';
            } else if (doc.type_fiche === 'Dépense') {
                print_format = 'fiche depense';
            } else if (doc.type_fiche === 'Régularisation') {
                print_format = 'fiche regularisation';
            } else if (doc.type_fiche === 'Provision') {
                print_format = 'Fiche Engagement';
            }
            else {
                frappe.msgprint(__('Unknown type_fiche, cannot determine print format.'));
                return;
            }

            // Generate the URL for the print view
            const url = frappe.urllib.get_full_url(
                `/printview?doctype=Fiche%20Budgetaire` +
                `&name=${encodeURIComponent(doc.name)}` +
                `&format=${encodeURIComponent(print_format)}` +
                `&no_letterhead=0`
            );

            // Open the print preview in a new window
            const w = window.open(url, '_blank');

            if (w) {
                w.onload = () => w.print();
            } else {
                frappe.msgprint(__('Popup blocked for {0}', [doc.name]));
            }
        }

        // Add a single button for printing
        listview.page.add_inner_button(
            '<i class="fa fa-print"></i> Imprimer fiche',
            () => { print_selected(); }
        );

        // Customize the print button style if needed
        const print_button = listview.page.wrapper.find('.dropdown-toggle:contains("Print")');

        if (print_button.length) {
            print_button.css({
                'background-color': '#007bff',
                'color': 'white',
                'border-color': '#007bff'
            });
        }

    }
};

