frappe.listview_settings['Budget Article'] = {
    onload(listview) {

        // Async function to print selected documents
        async function print_selected(print_format) {
            const selected = listview.get_checked_items();

            if (!selected.length) {
                frappe.msgprint(__('Please select at least one Budget Article to print.'));
                return;
            }

            // Loop through selected docs sequentially to avoid popup blocking
            for (const doc of selected) {
                const url = frappe.urllib.get_full_url(
                    `/printview?doctype=Budget Article` +
                    `&name=${encodeURIComponent(doc.name)}` +
                    `&format=${encodeURIComponent(print_format)}` +
                    `&no_letterhead=0`
                );

                const w = window.open(url, '_blank');

                if (w) {
                    // Trigger print after the window loads
                    w.onload = () => w.print();

                    // Optional: small delay to ensure print dialog triggers properly
                    await new Promise(r => setTimeout(r, 500));
                } else {
                    frappe.msgprint(__('Popup blocked for {0}', [doc.name]));
                }
            }
        }

        // Add dropdown buttons under "Print"
        listview.page.add_inner_button(__('Fiche Economie'), () => {
            print_selected('Fiche Economie');
        }, __('Print'));

        listview.page.add_inner_button(__('Fiche Regularisation'), () => {
            print_selected('Fiche Regularisation');
        }, __('Print'));

    }
};

frappe.ui.form.on('Faculte', {
    intitule_faculte(frm) {
        const value = frm.doc.intitule_faculte || '';

        // extraire UNIQUEMENT les lettres majuscules (accentuées incluses)
        const initials = value.match(/[A-ZÀÂÄÇÉÈÊËÎÏÔÖÙÛÜŸ]/g)?.join('') || '';

        frm.set_value('initiales_faculte', initials);
    }
});

frappe.ui.form.on('Annee Budgetaire', {
    onload: function(frm) {
        // Générer la liste des années de 2026 à 2100
        let years = [];
        for (let i = 2026; i <= 2100; i++) {
            years.push(i.toString());
        }
        frm.set_df_property('annee', 'options', years.join('\n'));
    },

    date_ouverture: function(frm) {
        if (frm.doc.date_ouverture) {
            // Empêche de choisir une date de clôture avant la date d'ouverture
            frm.set_df_property('date_cloture', 'min_date', frm.doc.date_ouverture);
        }
    }
});

frappe.ui.form.on('Annee Budgetaire', {
    date_ouverture: function(frm) {
        if (frm.doc.date_ouverture) {
            // Appliquer la borne minimale directement sur la définition du champ
            frm.fields_dict['date_cloture'].df.min_date = frm.doc.date_ouverture;
            // Rafraîchir le champ pour que le Date Picker recharge la contrainte
            frm.fields_dict['date_cloture'].refresh();
        }
    }
});

